mapper.insert:
INSERT IGNORE INTO heritage (name, name_hanja, category, period, location, thumbnail_url, ccba_kdcd, ccba_asno, ccba_ctcd)
VALUES (
    #{name}, #{nameHanja}, #{category}, #{period},
    ST_GeomFromText(CONCAT('POINT(', #{lat}, ' ', #{lng}, ')'), 4326), 
    #{thumbnailUrl}, #{ccbaKdcd}, #{ccbaAsno}, #{ccbaCtcd}
)

mapper.select:
SELECT id, heritage_id, content, depth_level, topic, parent_id, source
FROM heritage_descriptions
WHERE heritage_id = #{heritageId}
  AND source = 'AI_GENERATED'
  AND depth_level = #{depthLevel}
  AND topic = #{topic}
ORDER BY id DESC
LIMIT 1
